def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity == 0:
            priorities[i] = float('inf')
            continue
        if item > capacity:
            priorities[i] = float('inf')
        else:
            ratio = item / capacity
            priority = 0
            if ratio < 0.1:
                priority += 5 * ratio
            elif ratio < 0.5:
                priority += 10 * (0.5 - ratio)
            else:
                priority += 20 * (1 - ratio)**2
            if capacity % 2 == 0:
                priority *= 1.1
            else:
                priority *= 0.9
            sum_digits = sum(int(d) for d in str(int(capacity)) if d.isdigit())
            if sum_digits % 3 == 0:
                priority *= 1.2
            else:
                priority *= 0.8
            priorities[i] = priority
    max_priority = np.max(priorities[np.isfinite(priorities)]) if np.any(np.isfinite(priorities)) else 1
    for i in range(len(priorities)):
        if priorities[i] == float('inf'):
            priorities[i] = max_priority * 10
    return priorities
